// 集中实现 MappingFlags 的方法，确保字段不变量只在类型内部被维护。
impl MappingFlags {
    // READ 是内存管理依赖的固定常量，集中定义可以避免同一数值在多处漂移。
    pub const READ: Self = Self { bits: 1 << 0 };
    // WRITE 是内存管理依赖的固定常量，集中定义可以避免同一数值在多处漂移。
    pub const WRITE: Self = Self { bits: 1 << 1 };
    // EXECUTE 是内存管理依赖的固定常量，集中定义可以避免同一数值在多处漂移。
    pub const EXECUTE: Self = Self { bits: 1 << 2 };
    // GLOBAL 是内存管理依赖的固定常量，集中定义可以避免同一数值在多处漂移。
    pub const GLOBAL: Self = Self { bits: 1 << 3 };
    // USER 是内存管理依赖的固定常量，集中定义可以避免同一数值在多处漂移。
    pub const USER: Self = Self { bits: 1 << 4 };
    // KERNEL_IMAGE 是内存管理依赖的固定常量，集中定义可以避免同一数值在多处漂移。
    pub const KERNEL_IMAGE: Self = Self {
        bits: Self::READ.bits | Self::WRITE.bits | Self::EXECUTE.bits | Self::GLOBAL.bits,
    };
    // USER_TEXT 是内存管理依赖的固定常量，集中定义可以避免同一数值在多处漂移。
    pub const USER_TEXT: Self = Self {
        bits: Self::READ.bits | Self::EXECUTE.bits | Self::USER.bits,
    };
    // USER_DATA 是内存管理依赖的固定常量，集中定义可以避免同一数值在多处漂移。
    pub const USER_DATA: Self = Self {
        bits: Self::READ.bits | Self::WRITE.bits | Self::USER.bits,
    };
    // USER_STACK 是内存管理依赖的固定常量，集中定义可以避免同一数值在多处漂移。
    pub const USER_STACK: Self = Self {
        bits: Self::READ.bits | Self::WRITE.bits | Self::USER.bits,
    };

