    pub const fn user(read: bool, write: bool, execute: bool) -> Self {
        let mut bits = Self::USER.bits;
        if read {
            bits |= Self::READ.bits;
        }
        if write {
            bits |= Self::WRITE.bits;
        }
        if execute {
            bits |= Self::EXECUTE.bits;
        }

        Self { bits }
    }

