// align_down 是 内存管理 的辅助函数，负责 align down 相关的状态更新或结果计算。
const fn align_down(value: usize, align: usize) -> usize {
    value / align * align
}

// align_up 是 内存管理 的辅助函数，负责 align up 相关的状态更新或结果计算。
const fn align_up(value: usize, align: usize) -> usize {
    if value % align == 0 {
        value
    } else {
        align_down(value, align) + align
    }
}

