// 集中实现 UserMemoryRegion 的方法，确保字段不变量只在类型内部被维护。
impl UserMemoryRegion {
    // 构造 new 对应值，并在入口处建立字段之间的不变量。
    pub const fn new(
        start: usize,
        end: usize,
        permissions: MappingFlags,
    ) -> Result<Self, UserMemoryBlocker> {
        if start % PAGE_SIZE != 0 || end % PAGE_SIZE != 0 {
            Err(UserMemoryBlocker::UnalignedRegion)
        } else if start >= end {
            Err(UserMemoryBlocker::EmptyRegion)
        } else if !is_user_range(start, end) {
            Err(UserMemoryBlocker::RegionOutsideUserRange)
        } else {
            Ok(Self {
                start,
                end,
                permissions,
            })
        }
    }

    // 返回 start 字段或派生状态，让调用方无需直接访问内部结构。
    pub const fn start(self) -> usize {
        self.start
    }

    // 返回 end 字段或派生状态，让调用方无需直接访问内部结构。
    pub const fn end(self) -> usize {
        self.end
    }

    // 返回 byte len 字段或派生状态，让调用方无需直接访问内部结构。
    pub const fn byte_len(self) -> usize {
        self.end - self.start
    }

    // 返回 permissions 字段或派生状态，让调用方无需直接访问内部结构。
    pub const fn permissions(self) -> MappingFlags {
        self.permissions
    }

    // contains 是 内存管理 的辅助函数，负责 contains 相关的状态更新或结果计算。
    pub const fn contains(self, address: usize) -> bool {
        self.start <= address && address < self.end
    }

    // covers 是 内存管理 的辅助函数，负责 covers 相关的状态更新或结果计算。
    pub const fn covers(self, other: Self) -> bool {
        self.start <= other.start && other.end <= self.end
    }

    // overlaps 是 内存管理 的辅助函数，负责 overlaps 相关的状态更新或结果计算。
    pub const fn overlaps(self, other: Self) -> bool {
        self.start < other.end && other.start < self.end
    }
}

