// BootStaticExecutableCacheEntry 是 exec 启动路径 的状态载体，字段组合表达需要一起维护的不变量。
#[derive(Clone, Copy)]
struct BootStaticExecutableCacheEntry {
    path: VfsPathBuffer,
    abi: ExecutableAbi,
    result: bool,
}

// BootStaticExecutableCache 是 exec 启动路径 的状态载体，字段组合表达需要一起维护的不变量。
struct BootStaticExecutableCache {
    entries: [Option<BootStaticExecutableCacheEntry>; BOOT_DISCOVERY_STATIC_EXEC_CACHE_LIMIT],
    next: usize,
    len: usize,
}

// 集中实现 BootStaticExecutableCache 的方法，确保字段不变量只在类型内部被维护。
impl BootStaticExecutableCache {
    // 构造 exec 启动路径 的初始空状态，后续写入会从这个稳定基线开始。
    const fn empty() -> Self {
        Self {
            entries: [None; BOOT_DISCOVERY_STATIC_EXEC_CACHE_LIMIT],
            next: 0,
            len: 0,
        }
    }

    // 判断 is static boot executable 是否成立，让调用方在产生副作用前先做条件分支。
    fn is_static_boot_executable(
        &mut self,
        rootfs: &mut MountedRootfs,
        path: VfsPathBuffer,
        abi: ExecutableAbi,
    ) -> Result<bool, BootInitExecBlocker> {
        if let Some(result) = self.lookup(path, abi) {
            return Ok(result);
        }
        let result = read_static_boot_executable(rootfs, path, abi)?;
        self.insert(path, abi, result);
        Ok(result)
    }

    // lookup 是 exec 启动路径 的辅助函数，负责 lookup 相关的状态更新或结果计算。
    fn lookup(&self, path: VfsPathBuffer, abi: ExecutableAbi) -> Option<bool> {
        let mut index = 0usize;
        while index < self.len {
            if let Some(entry) = self.entries[index] {
                if entry.abi == abi && entry.path.bytes() == path.bytes() {
                    return Some(entry.result);
                }
            }
            index += 1;
        }
        None
    }

    // insert 是 exec 启动路径 的辅助函数，负责 insert 相关的状态更新或结果计算。
    fn insert(&mut self, path: VfsPathBuffer, abi: ExecutableAbi, result: bool) {
        self.entries[self.next] = Some(BootStaticExecutableCacheEntry { path, abi, result });
        self.next += 1;
        if self.next == self.entries.len() {
            self.next = 0;
        }
        if self.len < self.entries.len() {
            self.len += 1;
        }
    }
}

