// wake_futex_wait_bucket 是 调度器 的辅助函数，负责 wake futex wait bucket 相关的状态更新或结果计算。
pub(super) fn wake_futex_wait_bucket(
    channel: WaitChannel,
    bucket: usize,
    max_wake: usize,
) -> WaitWakeSummary {
    if max_wake == 0 {
        return WaitWakeSummary { woken: 0 };
    }

    let mut woken = 0usize;
    let mut mask = FUTEX_WAIT_SLOTS[bucket].load(Ordering::Acquire);
    while woken < max_wake {
        let Some((slot, bit, next_mask)) = take_lowest_slot_bit(mask) else {
            break;
        };
        if slot >= EDF_TASK_CAPACITY {
            FUTEX_WAIT_SLOTS[bucket].fetch_and(!bit, Ordering::AcqRel);
        } else if TASK_STATE[slot].load(Ordering::Acquire) != STATE_WAITING {
            FUTEX_WAIT_SLOTS[bucket].fetch_and(!bit, Ordering::AcqRel);
        } else if wait_channel_matches(slot, channel) {
            wake_waiting_slot(slot, WAKE_REASON_CHANNEL);
            woken += 1;
        } else if !slot_still_in_futex_bucket(slot, bucket) {
            FUTEX_WAIT_SLOTS[bucket].fetch_and(!bit, Ordering::AcqRel);
        }
        mask = next_mask;
    }
    WaitWakeSummary { woken }
}

// requeue_futex_wait_bucket 是 调度器 的辅助函数，负责 requeue futex wait bucket 相关的状态更新或结果计算。
pub(super) fn requeue_futex_wait_bucket(
    channel: WaitChannel,
    bucket: usize,
    requeue_key: usize,
    max_wake: usize,
    max_requeue: usize,
) -> FutexRequeueSummary {
    if max_wake == 0 && max_requeue == 0 {
        return FutexRequeueSummary {
            woken: 0,
            requeued: 0,
        };
    }

    let mut woken = 0usize;
    let mut requeued = 0usize;
    let mut mask = FUTEX_WAIT_SLOTS[bucket].load(Ordering::Acquire);
    while woken < max_wake || requeued < max_requeue {
        let Some((slot, bit, next_mask)) = take_lowest_slot_bit(mask) else {
            break;
        };
        if slot >= EDF_TASK_CAPACITY {
            FUTEX_WAIT_SLOTS[bucket].fetch_and(!bit, Ordering::AcqRel);
        } else if TASK_STATE[slot].load(Ordering::Acquire) != STATE_WAITING {
            FUTEX_WAIT_SLOTS[bucket].fetch_and(!bit, Ordering::AcqRel);
        } else if wait_channel_matches(slot, channel) {
            if woken < max_wake {
                wake_waiting_slot(slot, WAKE_REASON_CHANNEL);
                woken += 1;
            } else {
                FUTEX_WAIT_SLOTS[bucket].fetch_and(!bit, Ordering::AcqRel);
                TASK_WAIT_KEY0[slot].store(requeue_key, Ordering::Release);
                FUTEX_WAIT_SLOTS[futex_wait_bucket(requeue_key)].fetch_or(bit, Ordering::AcqRel);
                requeued += 1;
            }
        } else if !slot_still_in_futex_bucket(slot, bucket) {
            FUTEX_WAIT_SLOTS[bucket].fetch_and(!bit, Ordering::AcqRel);
        }
        mask = next_mask;
    }
    FutexRequeueSummary { woken, requeued }
}

// slot_still_in_futex_bucket 是 调度器 的辅助函数，负责 slot still in futex bucket 相关的状态更新或结果计算。
fn slot_still_in_futex_bucket(slot: usize, bucket: usize) -> bool {
    TASK_WAIT_KIND[slot].load(Ordering::Acquire) == WAIT_FUTEX
        && futex_wait_bucket(TASK_WAIT_KEY0[slot].load(Ordering::Acquire)) == bucket
}

