const RISCV_CONTEXT_FRAME_BYTES: usize = RISCV_CONTEXT_FRAME_WORDS * core::mem::size_of::<usize>();
// RISCV_CONTEXT_RA_SLOT 是内核核心代码依赖的固定常量，集中定义可以避免同一数值在多处漂移。
