const RISCV_CONTEXT_S0_SLOT: usize = 1;
// RISCV_CONTEXT_S1_SLOT 是内核核心代码依赖的固定常量，集中定义可以避免同一数值在多处漂移。
#[cfg(target_arch = "riscv64")]
const RISCV_CONTEXT_S1_SLOT: usize = 2;
// RISCV_CONTEXT_S2_SLOT 是内核核心代码依赖的固定常量，集中定义可以避免同一数值在多处漂移。
#[cfg(target_arch = "riscv64")]
const RISCV_CONTEXT_S2_SLOT: usize = 3;

