    .section .text.context_switch, "ax"
    .align 2
    .globl __riscv64_context_switch
__riscv64_context_switch:
    addi sp, sp, -112
    sd ra, 0(sp)
    sd s0, 8(sp)
    sd s1, 16(sp)
    sd s2, 24(sp)
    sd s3, 32(sp)
