    .align 2
    .globl __riscv64_context_first_run_trampoline
__riscv64_context_first_run_trampoline:
    mv a0, s0
    mv a1, s1
    la ra, __riscv64_context_first_run_return
    jr s2
__riscv64_context_first_run_return:
1:
    wfi
