// 汇总 内核核心代码 当前是否可用以及阻塞原因，启动流程据此决定是否启用该能力。
pub const fn readiness() -> HardwareReadiness {
    HardwareReadiness::NotReady(ReadinessReason::ContextSwitchNotBound)
