// switch_context 是 内核核心代码 的辅助函数，负责 switch context 相关的状态更新或结果计算。
pub fn switch_context(request: ContextSwitchRequest, mode: BoundaryMode) -> ContextSwitchState {
    match mode {
        BoundaryMode::Inspect => ContextSwitchState::Planned(request),
        BoundaryMode::Prepare => ContextSwitchState::Prepared(request),
        BoundaryMode::ApplyUnsafe => apply_context_switch(request),
    }
}

// prepare_first_run_context 是 内核核心代码 的辅助函数，负责 prepare first run context 相关的状态更新或结果计算。
pub fn prepare_first_run_context(
    request: ContextFirstRunRequest,
    mode: BoundaryMode,
) -> ContextFirstRunState {
    match mode {
        BoundaryMode::Inspect => ContextFirstRunState::Planned(request),
        BoundaryMode::Prepare => prepare_first_run_frame(request, false),
        BoundaryMode::ApplyUnsafe => prepare_first_run_frame(request, true),
    }
}

// apply_context_switch 是 内核核心代码 的辅助函数，负责 apply context switch 相关的状态更新或结果计算。
#[cfg(target_arch = "riscv64")]
fn apply_context_switch(request: ContextSwitchRequest) -> ContextSwitchState {
    let current = request.current();
    let next = request.next();
    unsafe {
        __riscv64_context_switch(
            current.saved_stack_pointer_slot() as *mut usize,
            next.kernel_stack_pointer(),
            satp_value(next.address_space_root()),
        );
    }
    ContextSwitchState::Applied(request)
}

// apply_context_switch 是 内核核心代码 的辅助函数，负责 apply context switch 相关的状态更新或结果计算。
#[cfg(not(target_arch = "riscv64"))]
fn apply_context_switch(_request: ContextSwitchRequest) -> ContextSwitchState {
    ContextSwitchState::Unsupported(
        crate::arch::contract::ContextSwitchUnsupported::HardwareExecutionNotVerified,
    )
}

// satp_value 是 内核核心代码 的辅助函数，负责 satp value 相关的状态更新或结果计算。
#[cfg(target_arch = "riscv64")]
const fn satp_value(root: crate::core::mm::PageTableRoot) -> usize {
    SATP_MODE_SV39 | (root.frame().start() >> 12)
}

// prepare_first_run_frame 是 内核核心代码 的辅助函数，负责 prepare first run frame 相关的状态更新或结果计算。
#[cfg(target_arch = "riscv64")]
fn prepare_first_run_frame(request: ContextFirstRunRequest, applied: bool) -> ContextFirstRunState {
    let frame_pointer = match first_run_frame_pointer(request) {
        Ok(frame_pointer) => frame_pointer,
        Err(blocker) => return ContextFirstRunState::NotReady(blocker),
    };

    unsafe {
        let frame = frame_pointer as *mut usize;
        let mut index = 0usize;
        while index < RISCV_CONTEXT_FRAME_WORDS {
            frame.add(index).write_volatile(0);
            index += 1;
        }
        frame
            .add(RISCV_CONTEXT_RA_SLOT)
            .write_volatile(__riscv64_context_first_run_trampoline as *const () as usize);
        frame
            .add(RISCV_CONTEXT_S0_SLOT)
            .write_volatile(request.arg0());
        frame
            .add(RISCV_CONTEXT_S1_SLOT)
            .write_volatile(request.arg1());
        frame
            .add(RISCV_CONTEXT_S2_SLOT)
            .write_volatile(request.entry());
    }

    match crate::arch::contract::ContextFirstRunFrame::new(frame_pointer) {
        Ok(frame) if applied => ContextFirstRunState::Applied(frame),
        Ok(frame) => ContextFirstRunState::Prepared(frame),
        Err(blocker) => ContextFirstRunState::NotReady(blocker),
    }
}

// prepare_first_run_frame 是 内核核心代码 的辅助函数，负责 prepare first run frame 相关的状态更新或结果计算。
#[cfg(not(target_arch = "riscv64"))]
fn prepare_first_run_frame(
    _request: ContextFirstRunRequest,
    _applied: bool,
) -> ContextFirstRunState {
    ContextFirstRunState::Unsupported(
        crate::arch::contract::ContextSwitchUnsupported::HardwareExecutionNotVerified,
    )
}

// first_run_frame_pointer 是 内核核心代码 的辅助函数，负责 first run frame pointer 相关的状态更新或结果计算。
#[cfg(target_arch = "riscv64")]
fn first_run_frame_pointer(
    request: ContextFirstRunRequest,
) -> Result<usize, crate::arch::contract::ContextFirstRunBlocker> {
    let frame_pointer = request
        .stack_end()
        .checked_sub(RISCV_CONTEXT_FRAME_BYTES)
        .ok_or(crate::arch::contract::ContextFirstRunBlocker::StackTooSmall)?;
    if frame_pointer < request.stack_start() {
        Err(crate::arch::contract::ContextFirstRunBlocker::StackTooSmall)
    } else if frame_pointer % crate::arch::contract::context::CONTEXT_STACK_ALIGN != 0 {
        Err(crate::arch::contract::ContextFirstRunBlocker::KernelStackUnaligned)
    } else {
        Ok(frame_pointer)
    }
}

