// SleepDuration 是 内核核心代码 的状态载体，字段组合表达需要一起维护的不变量。
#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct SleepDuration {
    seconds: u64,
    nanos: u32,
}

// 集中实现 SleepDuration 的方法，确保字段不变量只在类型内部被维护。
impl SleepDuration {
    // 构造 from linux timespec bytes 对应值，并在入口处建立字段之间的不变量。
    pub fn from_linux_timespec_bytes(raw: &[u8; 16]) -> Result<Self, SleepDurationError> {
        let seconds = i64::from_le_bytes([
            raw[0], raw[1], raw[2], raw[3], raw[4], raw[5], raw[6], raw[7],
        ]);
        let nanos = i64::from_le_bytes([
            raw[8], raw[9], raw[10], raw[11], raw[12], raw[13], raw[14], raw[15],
        ]);
        if seconds < 0 {
            return Err(SleepDurationError::InvalidTimespec);
        }
        if !(0..1_000_000_000).contains(&nanos) {
            return Err(SleepDurationError::InvalidTimespec);
        }

        Ok(Self {
            seconds: seconds as u64,
            nanos: nanos as u32,
        })
    }

    // 返回 is zero 字段或派生状态，让调用方无需直接访问内部结构。
    pub const fn is_zero(self) -> bool {
        self.seconds == 0 && self.nanos == 0
    }

    // 返回 ceil micros 字段或派生状态，让调用方无需直接访问内部结构。
    pub fn ceil_micros(self) -> Result<usize, SleepDurationError> {
        let seconds = if self.seconds > usize::MAX as u64 / 1_000_000 {
            return Err(SleepDurationError::DurationOverflow);
        } else {
            self.seconds as usize
        };
        let second_micros = seconds
            .checked_mul(1_000_000)
            .ok_or(SleepDurationError::DurationOverflow)?;
        let nano_micros = (self.nanos as usize).div_ceil(1000);
        second_micros
            .checked_add(nano_micros)
            .ok_or(SleepDurationError::DurationOverflow)
    }
}

