#[cfg(target_arch = "riscv64")]
unsafe fn apply_user_return_with_trap_stack(pending: PendingUserEntry, trap_stack_top: usize) -> ! {
    let status = initial_user_status();
    let frame = RiscvUserTrapFrame::from_user_entry(pending, status);
    core::arch::asm!("csrw sscratch, {0}", in(reg) trap_stack_top, options(nostack, preserves_flags));
    __riscv64_restore_user_trap_frame(&frame)
