use core::sync::atomic::{AtomicUsize, Ordering};

// 标准输出 fd 编号，用户输出适配层用它识别普通输出。
const STDOUT_FD: usize = 1;
// 标准错误 fd 编号，用户输出适配层用它识别错误输出。
const STDERR_FD: usize = 2;

// OutputWriter 给复杂类型取语义化名称，让函数签名更接近业务含义。
type OutputWriter = fn(&[u8]) -> usize;

// USER_OUTPUT_WRITER 保存跨调用共享的状态，访问时必须保持初始化顺序和并发语义清晰。
static USER_OUTPUT_WRITER: AtomicUsize = AtomicUsize::new(0);

// UserOutputError 汇总本路径的失败原因，便于统一转换为 errno 或阻塞状态。
#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum UserOutputError {
    SinkMissing,
    UnsupportedFd,
}

// install_user_output_writer 是 评测输出适配 的辅助函数，负责 install user output writer 相关的状态更新或结果计算。
pub fn install_user_output_writer(writer: OutputWriter) {
    USER_OUTPUT_WRITER.store(writer as usize, Ordering::Release);
}

// 写入 user fd，同时集中处理短写、地址错误或输出失败。
pub fn write_user_fd(fd: usize, bytes: &[u8]) -> Result<usize, UserOutputError> {
    if fd != STDOUT_FD && fd != STDERR_FD {
        return Err(UserOutputError::UnsupportedFd);
    }

    let raw = USER_OUTPUT_WRITER.load(Ordering::Acquire);
    if raw == 0 {
        return Err(UserOutputError::SinkMissing);
    }

    let writer: OutputWriter = unsafe { core::mem::transmute(raw) };
    Ok(writer(bytes))
}

// 访问 configure normal task 寄存器，集中处理 volatile 读写和偏移计算。
pub fn configure_normal_task(pid: Pid, now_micros: usize) -> Result<(), SchedulerError> {
    ensure_task_registered(pid, now_micros)?;
    let slot = slot_for_pid(pid)?;
    let deadline = now_micros
        .checked_add(DEFAULT_TASK_PERIOD_MICROS)
        .ok_or(SchedulerError::DeadlineOverflow)?;
    TASK_RUNTIME_MICROS[slot].store(DEFAULT_TASK_PERIOD_MICROS, Ordering::Release);
    TASK_RELATIVE_DEADLINE_MICROS[slot].store(DEFAULT_TASK_PERIOD_MICROS, Ordering::Release);
    TASK_PERIOD_MICROS[slot].store(DEFAULT_TASK_PERIOD_MICROS, Ordering::Release);
    TASK_DEADLINE_MICROS[slot].store(deadline, Ordering::Release);
    TASK_POLICY[slot].store(0, Ordering::Release);
    Ok(())
}

// 访问 configure deadline task 寄存器，集中处理 volatile 读写和偏移计算。
pub fn configure_deadline_task(
    pid: Pid,
    now_micros: usize,
    runtime_micros: usize,
    relative_deadline_micros: usize,
    period_micros: usize,
) -> Result<(), SchedulerError> {
    if runtime_micros == 0
        || relative_deadline_micros == 0
        || period_micros == 0
        || runtime_micros > relative_deadline_micros
        || relative_deadline_micros > period_micros
    {
        return Err(SchedulerError::InvalidDeadline);
    }
    ensure_task_registered(pid, now_micros)?;
    let slot = slot_for_pid(pid)?;
    let deadline = now_micros
        .checked_add(relative_deadline_micros)
        .ok_or(SchedulerError::DeadlineOverflow)?;
    TASK_RUNTIME_MICROS[slot].store(runtime_micros, Ordering::Release);
    TASK_RELATIVE_DEADLINE_MICROS[slot].store(relative_deadline_micros, Ordering::Release);
    TASK_PERIOD_MICROS[slot].store(period_micros, Ordering::Release);
    TASK_DEADLINE_MICROS[slot].store(deadline, Ordering::Release);
    TASK_POLICY[slot].store(1, Ordering::Release);
    Ok(())
}

// task_scheduling_parameters 是 调度器 的辅助函数，负责 task scheduling parameters 相关的状态更新或结果计算。
pub fn task_scheduling_parameters(pid: Pid) -> Result<TaskSchedulingParameters, SchedulerError> {
    let slot = slot_for_pid(pid)?;
    Ok(TaskSchedulingParameters {
        policy: if TASK_POLICY[slot].load(Ordering::Acquire) == 0 {
            SchedulerPolicy::Normal
        } else {
            SchedulerPolicy::Deadline
        },
        runtime_micros: TASK_RUNTIME_MICROS[slot].load(Ordering::Acquire),
        relative_deadline_micros: TASK_RELATIVE_DEADLINE_MICROS[slot].load(Ordering::Acquire),
        period_micros: TASK_PERIOD_MICROS[slot].load(Ordering::Acquire),
    })
}

// mark_task_running 是 调度器 的辅助函数，负责 mark task running 相关的状态更新或结果计算。
pub fn mark_task_running(pid: Pid, now_micros: usize) -> Result<EdfTask, SchedulerError> {
    let task = ensure_task_registered(pid, now_micros)?;
    let slot = slot_for_pid(pid)?;
    match TASK_STATE[slot].load(Ordering::Acquire) {
        STATE_PREPARED => return Err(SchedulerError::TaskPrepared),
        STATE_SLEEPING => return Err(SchedulerError::TaskSleeping),
        STATE_WAITING => return Err(SchedulerError::TaskWaiting),
        _ => {}
    }
    clear_task_wait_slot(slot);
    store_task_state(slot, STATE_RUNNING);
    Ok(task)
}

// activate_prepared_task 是 调度器 的辅助函数，负责 activate prepared task 相关的状态更新或结果计算。
pub fn activate_prepared_task(pid: Pid) -> Result<EdfTask, SchedulerError> {
    let slot = slot_for_pid(pid)?;
    if TASK_STATE[slot].load(Ordering::Acquire) != STATE_PREPARED {
        return Err(SchedulerError::TaskNotPrepared);
    }
    let _ = task_context_at(slot)?;
    clear_task_wake_slot(slot);
    clear_task_wait_slot(slot);
    store_task_state(slot, STATE_RUNNABLE);
    Ok(task_at(slot, pid.value()))
}

// mark_task_runnable 是 调度器 的辅助函数，负责 mark task runnable 相关的状态更新或结果计算。
pub fn mark_task_runnable(pid: Pid) -> Result<EdfTask, SchedulerError> {
    let slot = slot_for_pid(pid)?;
    if TASK_STATE[slot].load(Ordering::Acquire) == STATE_PREPARED {
        return Err(SchedulerError::TaskPrepared);
    }
    clear_task_wake_slot(slot);
    clear_task_wait_slot(slot);
    store_task_state(slot, STATE_RUNNABLE);
    Ok(task_at(slot, pid.value()))
}

// pick_next_task 是 调度器 的辅助函数，负责 pick next task 相关的状态更新或结果计算。
pub fn pick_next_task() -> Option<EdfTask> {
    let slot = earliest_runnable_slot()?;
    let pid_value = TASK_PID[slot].load(Ordering::Acquire);
    store_task_state(slot, STATE_RUNNING);
    Some(task_at(slot, pid_value))
