// yield_running_task 是 调度器 的辅助函数，负责 yield running task 相关的状态更新或结果计算。
pub fn yield_running_task(pid: Pid, now_micros: usize) -> Result<EdfTask, SchedulerError> {
    let slot = slot_for_pid(pid)?;
    if TASK_STATE[slot].load(Ordering::Acquire) != STATE_RUNNING {
        return Err(SchedulerError::NotRunning);
    }
    let period = TASK_PERIOD_MICROS[slot].load(Ordering::Acquire);
    let current_deadline = TASK_DEADLINE_MICROS[slot].load(Ordering::Acquire);
