    while index < entries {
        let offset = EXT4_EXTENT_HEADER_SIZE + index * EXT4_EXTENT_INDEX_SIZE;
        if offset + EXT4_EXTENT_INDEX_SIZE > node.len() {
            return Err(Ext4Error::MetadataCorrupt);
        }
