#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub(super) struct Ext4Inode {
    pub(super) number: u32,
    pub(super) mode: u16,
    pub(super) size: u64,
    pub(super) links: u16,
    pub(super) blocks: u64,
    pub(super) flags: u32,
    pub(super) extent_root: [u8; 60],
}

// 集中实现 Ext4Inode 的方法，确保字段不变量只在类型内部被维护。
impl Ext4Inode {
    // parse 是 EXT4 解析器 的辅助函数，负责 parse 相关的状态更新或结果计算。
    pub(super) fn parse(number: u32, bytes: &[u8]) -> Result<Self, Ext4Error> {
        if bytes.len() < 128 {
            return Err(Ext4Error::MetadataCorrupt);
        }

        let mode = read_u16(bytes, 0)?;
        let size_lo = read_u32(bytes, 4)? as u64;
        let size_hi = read_u32(bytes, 108)? as u64;
        let links = read_u16(bytes, 26)?;
        let blocks_lo = read_u32(bytes, 28)? as u64;
        let blocks_hi = if bytes.len() >= 120 {
            read_u16(bytes, 116)? as u64
        } else {
            0
        };
        let flags = read_u32(bytes, 32)?;
        let mut extent_root = [0u8; 60];
        extent_root.copy_from_slice(&bytes[40..100]);
        Ok(Self {
            number,
            mode,
            size: size_lo | (size_hi << 32),
            links,
            blocks: blocks_lo | (blocks_hi << 32),
            flags,
            extent_root,
        })
    }

    // 判断 is dir 是否成立，让调用方在产生副作用前先做条件分支。
    pub(super) const fn is_dir(self) -> bool {
        self.mode & EXT4_S_IFMT == EXT4_S_IFDIR
    }

    // 判断 is regular 是否成立，让调用方在产生副作用前先做条件分支。
    pub(super) const fn is_regular(self) -> bool {
        self.mode & EXT4_S_IFMT == EXT4_S_IFREG
    }

    // 判断 is symlink 是否成立，让调用方在产生副作用前先做条件分支。
    pub(super) const fn is_symlink(self) -> bool {
        self.mode & EXT4_S_IFMT == EXT4_S_IFLNK
    }

    // executable 是 EXT4 解析器 的辅助函数，负责 executable 相关的状态更新或结果计算。
    pub(super) const fn executable(self) -> bool {
        self.mode & EXT4_EXEC_BITS != 0
    }
}

