// kernel_image_range 是 内核编排层 的辅助函数，负责 kernel image range 相关的状态更新或结果计算。
pub fn kernel_image_range() -> Result<KernelImageRange, KernelImageRangeError> {
    let start = core::ptr::addr_of!(__kernel_start) as usize;
    let end = core::ptr::addr_of!(__kernel_end) as usize;

    KernelImageRange::new(start, end)
}

// kernel_layout 是 内核编排层 的辅助函数，负责 kernel layout 相关的状态更新或结果计算。
pub fn kernel_layout() -> Result<KernelLayout, KernelImageRangeError> {
    let image = kernel_image_range()?;
    let text = KernelSectionRange::new(
        core::ptr::addr_of!(__text_start) as usize,
        core::ptr::addr_of!(__text_end) as usize,
    )?;
    let rodata = KernelSectionRange::new(
        core::ptr::addr_of!(__rodata_start) as usize,
        core::ptr::addr_of!(__rodata_end) as usize,
    )?;
    let data = KernelSectionRange::new(
        core::ptr::addr_of!(__data_start) as usize,
        core::ptr::addr_of!(__data_end) as usize,
    )?;
    let bss = KernelSectionRange::new(
        core::ptr::addr_of!(__bss_start) as usize,
        core::ptr::addr_of!(__bss_end) as usize,
    )?;

    KernelLayout::new(image, text, rodata, data, bss)
}

use std::env;
use std::io::{self, Write};
use std::path::PathBuf;

// 构建脚本入口声明 Cargo 重跑条件和链接参数，确保目标变更能触发重新构建。
fn main() {
    emit("cargo:rerun-if-changed=build/riscv64.ld");
    emit("cargo:rerun-if-changed=build/loongarch64.ld");

    let target = env::var("TARGET").unwrap_or_default();
    let manifest_dir = PathBuf::from(env::var("CARGO_MANIFEST_DIR").unwrap());

    match target.as_str() {
        "riscv64gc-unknown-none-elf" => link_kernel(
            "source-riscv64-kernel",
            manifest_dir.join("build").join("riscv64.ld"),
        ),
        "loongarch64-unknown-none" => link_kernel(
            "source-loongarch64-kernel",
            manifest_dir.join("build").join("loongarch64.ld"),
        ),
        _ => {}
    }
}

// 为指定内核二进制追加 linker script 参数，让每个架构使用自己的内存布局。
fn link_kernel(bin: &str, linker_script: PathBuf) {
    emit(&format!(
        "cargo:rustc-link-arg-bin={bin}=-T{}",
        linker_script.display(),
    ));
}

// 向 Cargo 输出一行构建脚本指令，并统一补换行。
fn emit(line: &str) {
    let mut out = io::stdout().lock();
    out.write_all(line.as_bytes()).unwrap();
    out.write_all(b"\n").unwrap();
}

/* 指定链接产物的目标架构，确保链接器生成与启动汇编匹配的机器码。 */
OUTPUT_ARCH(riscv)
/* 声明内核入口符号，固件或加载器跳转后会从这个符号开始执行。 */
ENTRY(_start)

/* 开始定义内核镜像的内存布局，后面的段顺序会直接影响运行地址。 */
SECTIONS
{
  /* QEMU virt 搭配 OpenSBI 时，内核按惯例加载到 0x80200000。 */
  . = 0x80200000;
  __kernel_start = .;

  /* 先放汇编入口，再放所有 Rust/代码文本段。 */
  /* 布置 代码段，把同类输入节收拢到连续地址范围，方便启动代码定位边界。 */
  .text : ALIGN(4K) {
    __text_start = .;
    *(.text.entry)
    *(.text .text.*)
    __text_end = .;
  }

  /* 只读常量按页对齐，方便建立简单内核映射。 */
  /* 布置 只读数据段，把同类输入节收拢到连续地址范围，方便启动代码定位边界。 */
  .rodata : ALIGN(4K) {
    __rodata_start = .;
    *(.rodata .rodata.*)
    __rodata_end = .;
  }

  /* 可写的已初始化数据。 */
  /* 布置 已初始化数据段，把同类输入节收拢到连续地址范围，方便启动代码定位边界。 */
  .data : ALIGN(4K) {
    __data_start = .;
    *(.sdata .sdata.*)
    *(.data .data.*)
    __data_end = .;
  }

  /* 零初始化数据，包括汇编生成的 boot/trap 栈。 */
  /* 布置 零初始化数据段，把同类输入节收拢到连续地址范围，方便启动代码定位边界。 */
  .bss : ALIGN(4K) {
    __bss_start = .;
    *(.sbss .sbss.*)
    *(.bss .bss.*)
    *(COMMON)
    __bss_end = .;
  }

  __kernel_end = .;

  /* 裸机内核镜像不需要这些段。 */
  /DISCARD/ : {
    *(.eh_frame)
    *(.comment)
  }
}

