//! LoongArch virtio-pci block provider for the QEMU `virt` machine.
//!
//! Direct kernel boot has no PCI firmware, so this provider discovers the
//! device through ECAM, assigns its memory BAR, and initializes a modern
//! virtio queue before issuing synchronous boot/rootfs reads.

use core::sync::atomic::{compiler_fence, Ordering};

use crate::arch::contract::{HardwareReadiness, ReadinessReason};
use crate::core::block::{
    BlockIoError, BlockReadCompletion, BlockReadRequest, BlockSector, BLOCK_SECTOR_SIZE,
};

// PCI_ECAM_BASE 表示地址或页布局参数，底层地址计算必须和它保持一致。
const PCI_ECAM_BASE: usize = 0x2000_0000;
// PCI_BUS_COUNT 固定长度或数量边界，相关检查统一引用这个约束。
const PCI_BUS_COUNT: usize = 128;
// PCI_DEVICE_COUNT 固定长度或数量边界，相关检查统一引用这个约束。
const PCI_DEVICE_COUNT: usize = 32;
// PCI_FUNCTION_COUNT 固定长度或数量边界，相关检查统一引用这个约束。
const PCI_FUNCTION_COUNT: usize = 8;
// PCI_CONFIG_VENDOR_ID 是 PCI 配置空间寄存器偏移，VirtIO 设备探测按它读取配置头字段。
const PCI_CONFIG_VENDOR_ID: usize = 0x00;
// PCI_CONFIG_DEVICE_ID 是 PCI 配置空间寄存器偏移，VirtIO 设备探测按它读取配置头字段。
const PCI_CONFIG_DEVICE_ID: usize = 0x02;
// PCI_CONFIG_COMMAND 是 PCI 配置空间寄存器偏移，VirtIO 设备探测按它读取配置头字段。
const PCI_CONFIG_COMMAND: usize = 0x04;
// PCI_CONFIG_STATUS 是 PCI 配置空间寄存器偏移，VirtIO 设备探测按它读取配置头字段。
const PCI_CONFIG_STATUS: usize = 0x06;
// PCI_CONFIG_HEADER_TYPE 是 PCI 配置空间寄存器偏移，VirtIO 设备探测按它读取配置头字段。
const PCI_CONFIG_HEADER_TYPE: usize = 0x0e;
// PCI_CONFIG_BAR0 是 PCI 配置空间寄存器偏移，VirtIO 设备探测按它读取配置头字段。
const PCI_CONFIG_BAR0: usize = 0x10;
// PCI_CONFIG_CAPABILITIES 是 PCI 配置空间寄存器偏移，VirtIO 设备探测按它读取配置头字段。
const PCI_CONFIG_CAPABILITIES: usize = 0x34;
// PCI_STATUS_CAPABILITIES 是 PCI 配置头中的标志位，用来判断或打开设备能力。
const PCI_STATUS_CAPABILITIES: u16 = 1 << 4;
// PCI_COMMAND_MEMORY_SPACE 是 PCI 配置头中的标志位，用来判断或打开设备能力。
const PCI_COMMAND_MEMORY_SPACE: u16 = 1 << 1;
// PCI_COMMAND_BUS_MASTER 是 PCI 配置头中的标志位，用来判断或打开设备能力。
const PCI_COMMAND_BUS_MASTER: u16 = 1 << 2;
