const PCI_COMMAND_INTERRUPT_DISABLE: u16 = 1 << 10;
// PCI_HEADER_MULTIFUNCTION 是 PCI 配置头中的标志位，用来判断或打开设备能力。
const PCI_HEADER_MULTIFUNCTION: u8 = 1 << 7;
// PCI_VENDOR_VIRTIO 是 VirtIO PCI 设备识别值，扫描总线时用它确认块设备类型。
const PCI_VENDOR_VIRTIO: u16 = 0x1af4;
// PCI_DEVICE_VIRTIO_BLOCK_TRANSITIONAL 是 VirtIO PCI 设备识别值，扫描总线时用它确认块设备类型。
const PCI_DEVICE_VIRTIO_BLOCK_TRANSITIONAL: u16 = 0x1001;
// PCI_DEVICE_VIRTIO_BLOCK_MODERN 是 VirtIO PCI 设备识别值，扫描总线时用它确认块设备类型。
const PCI_DEVICE_VIRTIO_BLOCK_MODERN: u16 = 0x1042;
// PCI_CAP_ID_VENDOR_SPECIFIC 是 PCI capability 类型编号，用来识别厂商扩展能力。
const PCI_CAP_ID_VENDOR_SPECIFIC: u8 = 0x09;
// PCI_BAR_COUNT 固定长度或数量边界，相关检查统一引用这个约束。
const PCI_BAR_COUNT: usize = 6;
// PCI_BAR_IO_SPACE 描述 PCI BAR 的类型或地址掩码，分配 MMIO 窗口时必须按它解释 BAR 值。
const PCI_BAR_IO_SPACE: u32 = 1;
// PCI_BAR_MEMORY_TYPE_MASK 描述 PCI BAR 的类型或地址掩码，分配 MMIO 窗口时必须按它解释 BAR 值。
