// first_relative_tool_name 是 exec 启动路径 的辅助函数，负责 first relative tool name 相关的状态更新或结果计算。
pub(super) fn first_relative_tool_name(
    script: &[u8],
    out: &mut [u8; BOOT_DISCOVERY_NAME_MAX],
) -> Option<usize> {
    let mut cursor = 0usize;
    while let Some(token) = next_script_token(script, &mut cursor) {
        if token.len() <= 2 || !token.starts_with(b"./") {
            continue;
        }
        let name = &token[2..];
        if name.is_empty() || name.len() > out.len() || name_contains_separator(name) {
            continue;
        }
        out[..name.len()].copy_from_slice(name);
        return Some(name.len());
    }
    None
}

// script_invokes_nested_script 是 exec 启动路径 的辅助函数，负责 script invokes nested script 相关的状态更新或结果计算。
pub(super) fn script_invokes_nested_script(script: &[u8]) -> bool {
    let mut cursor = 0usize;
    let mut saw_cd = false;
    while let Some(token) = next_script_token(script, &mut cursor) {
        if trim_script_token_quotes(token) == b"cd" {
            saw_cd = true;
            continue;
        }
        if saw_cd && token_is_relative_script(token) {
            return true;
        }
        saw_cd = false;
    }
    false
}

// token_is_relative_script 是 exec 启动路径 的辅助函数，负责 token is relative script 相关的状态更新或结果计算。
fn token_is_relative_script(token: &[u8]) -> bool {
    let token = trim_script_token_quotes(token);
    token.starts_with(b"./") && token.ends_with(b".sh")
}

// script_uses_single_boot_tool 是 exec 启动路径 的辅助函数，负责 script uses single boot tool 相关的状态更新或结果计算。
pub(super) fn script_uses_single_boot_tool(
    rootfs: &mut MountedRootfs,
    directory: VfsPathBuffer,
    script: &[u8],
    tool_name: &[u8],
) -> Result<bool, BootInitExecBlocker> {
    let mut cursor = 0usize;
    let mut saw_tool = false;
    while let Some(token) = next_script_token(script, &mut cursor) {
        if token_embeds_relative_command_assignment(token) {
            return Ok(false);
        }
        let token = trim_script_token_quotes(token);
        if token.len() <= 2 || !token.starts_with(b"./") {
            continue;
        }
        let name = &token[2..];
        if name.is_empty() || name_contains_separator(name) {
            continue;
        }
        if name == tool_name {
            saw_tool = true;
            continue;
        }
        let path = resolve_boot_child_path(directory, name)?;
        let file = match rootfs.open(path.as_path().map_err(BootInitExecBlocker::VfsPath)?) {
            Ok(file) => file,
            Err(VfsError::PathNotFound) => continue,
            Err(error) => return Err(BootInitExecBlocker::Rootfs(error)),
        };
        let identity = file.identity();
        if identity.is_directory() {
            continue;
        }
        if identity.executable() {
            return Ok(false);
        }
    }
    Ok(saw_tool)
}

// script_helper_invocation_summary 是 exec 启动路径 的辅助函数，负责 script helper invocation summary 相关的状态更新或结果计算。
pub(super) fn script_helper_invocation_summary(
    rootfs: &mut MountedRootfs,
    directory: VfsPathBuffer,
    script: &[u8],
    abi: ExecutableAbi,
    static_cache: &mut BootStaticExecutableCache,
) -> Result<ScriptHelperInvocationSummary, BootInitExecBlocker> {
    let mut cursor = 0usize;
    let mut helper_paths = [VfsPathBuffer::root(); BOOT_DISCOVERY_HELPER_SCRIPT_LIMIT];
    let mut helper_count = 0usize;
    let mut summary = ScriptHelperInvocationSummary {
        has_helpers: false,
        all_helpers_short: true,
    };
    while let Some(token) = next_script_token(script, &mut cursor) {
        let token = trim_script_token_quotes(token);
        if !token_is_relative_script(token) {
            continue;
        }
        let name = &token[2..];
        if name.is_empty() || name_contains_separator(name) {
            continue;
        }
        let path = resolve_boot_child_path(directory, name)?;
        if helper_script_seen(&helper_paths[..helper_count], path) {
            continue;
        }
        if helper_count >= helper_paths.len() {
            return Ok(Default::default());
        }
        let Some(classification) =
            helper_script_path_classification(rootfs, directory, path, abi, static_cache)?
        else {
            return Ok(Default::default());
        };
        helper_paths[helper_count] = path;
        helper_count += 1;
        summary.has_helpers = true;

