// exec_from_syscall 是 系统调用运行时 的辅助函数，负责 exec from syscall 相关的状态更新或结果计算。
pub fn exec_from_syscall(request: ExecRequest) -> Result<PendingUserEntry, isize> {
    let bsp = active_bsp()?;
    let memory = active_memory_mut()?;
    let resolved = resolve_runtime_path_from_active_cwd(
        request.dirfd(),
        request.path(),
        RuntimeFinalSymlink::Follow,
    )
    .map_err(map_runtime_errno)?;
    let (exec_path, file) = open_exec_request_file(resolved)?;
    if !file.identity().is_regular() {
        return Err(SyscallError::Invalid.errno());
    }

    let rootfs = active_rootfs_mut().map_err(map_runtime_errno)?;
    let file_buffer = syscall_exec_buffer();
    let read = rootfs
        .read_all(&file, file_buffer)
        .map_err(VfsRuntimeError::Vfs)
        .map_err(map_runtime_errno)?;
    let bytes = read.bytes();
    if let Some(script) = Shebang::parse(&file_buffer[..bytes]) {
        return exec_shebang_script(rootfs, bsp, memory, exec_path, request, script);
    }
    if !file.identity().executable() {
        return Err(SyscallError::ExecFormat.errno());
    }
    let mut argv = [&[][..]; SYSCALL_EXEC_ARG_COUNT];
    let mut argc = 0usize;
    while argc < request.arg_count() && argc < argv.len() {
        if let Some(arg) = request.arg(argc) {
            argv[argc] = arg;
        }
        argc += 1;
    }
    let mut envp = [&[][..]; SYSCALL_EXEC_ENV_COUNT];
    let envc = fill_request_envp(&request, &mut envp);

    let abi = executable_abi(bsp.snapshot().boot().architecture());
    if let Some(interpreter) = executable_interpreter(Some(&file_buffer[..bytes]), abi)
        .map_err(|_| SyscallError::ExecFormat.errno())?
    {
        return exec_interpreted_elf(
            rootfs,
            bsp,
            memory,
            exec_path,
            bytes,
            &argv[..argc],
            &envp[..envc],
            interpreter.path(),
        );
    }

    let exec_identity = single_exec_identity_snapshot();
    match load_exec_image(
        bsp,
        memory,
        &file_buffer[..bytes],
        &argv[..argc],
        &envp[..envc],
    ) {
        Ok(pending) => {
            single_restore_exec_identity(exec_identity);
            single_reset_signal_state_for_exec();
            set_active_exec_path(exec_path);
            set_active_cmdline_from_argv(&argv[..argc]);
            save_active_runtime_for_task(single_pid()).map_err(map_task_runtime_errno)?;
            wake_vfork_parent_after_exec();
            Ok(pending)
        }
        Err(errno) => Err(errno),
    }
}

// 处理 open exec request file 的文件资源，统一 fd 所有权、权限检查和错误返回。
fn open_exec_request_file(
    path: VfsPathBuffer,
) -> Result<(VfsPathBuffer, OpenFileDescription), isize> {
    let direct_open = {
        let path = path
            .as_path()
            .map_err(VfsRuntimeError::Vfs)
            .map_err(map_runtime_errno)?;
        active_rootfs_mut()
            .map_err(map_runtime_errno)?
            .open(path)
            .map_err(VfsRuntimeError::Vfs)
    };
    match direct_open {
        Ok(file) => Ok((path, file)),
        Err(VfsRuntimeError::Vfs(VfsError::PathNotFound)) => {
            let alias = {
                let path = path
                    .as_path()
                    .map_err(VfsRuntimeError::Vfs)
                    .map_err(map_runtime_errno)?;
                active_exec_alias_for_missing_path(path).map_err(map_runtime_errno)?
            };
            match alias {
                Some((target, file, _)) => Ok((target, file)),
                None => Err(SyscallError::NoEntry.errno()),
            }
        }
        Err(error) => Err(map_runtime_errno(error)),
    }
}

