// RWF_HIPRI 是系统调用兼容层依赖的固定常量，集中定义可以避免同一数值在多处漂移。
const RWF_HIPRI: usize = 0x01;
// RWF_DSYNC 是系统调用兼容层依赖的固定常量，集中定义可以避免同一数值在多处漂移。
const RWF_DSYNC: usize = 0x02;
// RWF_SYNC 是系统调用兼容层依赖的固定常量，集中定义可以避免同一数值在多处漂移。
const RWF_SYNC: usize = 0x04;
// RWF_NOWAIT 是系统调用兼容层依赖的固定常量，集中定义可以避免同一数值在多处漂移。
const RWF_NOWAIT: usize = 0x08;
// RWF_APPEND 是系统调用兼容层依赖的固定常量，集中定义可以避免同一数值在多处漂移。
const RWF_APPEND: usize = 0x10;
// PREADV2_SUPPORTED_FLAGS 表示 ABI 标志位或掩码，解析用户选项时用它拆分权限和行为。
const PREADV2_SUPPORTED_FLAGS: usize = RWF_HIPRI;
// PWRITEV2_SUPPORTED_FLAGS 表示 ABI 标志位或掩码，解析用户选项时用它拆分权限和行为。
const PWRITEV2_SUPPORTED_FLAGS: usize = RWF_HIPRI | RWF_DSYNC | RWF_SYNC | RWF_APPEND;
// RWF_COMMON_UNSUPPORTED_FLAGS 表示 ABI 标志位或掩码，解析用户选项时用它拆分权限和行为。
const RWF_COMMON_UNSUPPORTED_FLAGS: usize = RWF_NOWAIT;

// 校验 preadv2 flags，提前拒绝越界、空指针或不受支持的组合。
fn validate_preadv2_flags(flags: usize) -> Result<(), SyscallError> {
    if flags & !(PREADV2_SUPPORTED_FLAGS | RWF_COMMON_UNSUPPORTED_FLAGS) != 0 {
        return Err(SyscallError::Invalid);
    }
    if flags & RWF_COMMON_UNSUPPORTED_FLAGS != 0 {
        return Err(SyscallError::NotSupported);
    }
